# Adaptive rejection sampling for univariate log-concave densities.
# Reference: Gilks and Wild (1992), Applied Statistics 41(2), 337-348.

.ars_make_density_function <- function(density, env) {
  if (is.function(density)) {
    return(density)
  }

  if (inherits(density, "formula")) {
    expr <- density[[length(density)]]
    formula_env <- environment(density)
    if (is.null(formula_env)) {
      formula_env <- env
    }
    return(function(x) eval(expr, envir = list(x = x), enclos = formula_env))
  }

  if (is.expression(density)) {
    expr <- density[[1L]]
    return(function(x) eval(expr, envir = list(x = x), enclos = env))
  }

  if (is.call(density) || is.name(density)) {
    expr <- density
    return(function(x) eval(expr, envir = list(x = x), enclos = env))
  }

  if (is.character(density) && length(density) == 1L) {
    obj <- get0(density, envir = env, inherits = TRUE)
    if (is.function(obj)) {
      return(obj)
    }
    expr <- parse(text = density)[[1L]]
    return(function(x) eval(expr, envir = list(x = x), enclos = env))
  }

  stop("density must be a function, formula, expression, call, or function name", call. = FALSE)
}

.ars_validate_domain <- function(domain) {
  if (!is.numeric(domain) || length(domain) != 2L || any(is.na(domain))) {
    stop("domain must be a numeric vector of length 2", call. = FALSE)
  }
  if (!(domain[1L] < domain[2L])) {
    stop("domain lower bound must be smaller than upper bound", call. = FALSE)
  }
  domain
}

.ars_validate_n <- function(n) {
  if (!is.numeric(n) || length(n) != 1L || !is.finite(n) || is.na(n)) {
    stop("n must be a single finite positive integer", call. = FALSE)
  }
  if (n <= 0 || abs(n - round(n)) > .Machine$double.eps^0.5) {
    stop("n must be a positive integer", call. = FALSE)
  }
  as.integer(round(n))
}

.ars_default_initial <- function(domain) {
  lower <- domain[1L]
  upper <- domain[2L]
  if (is.finite(lower) && is.finite(upper)) {
    return(lower + (upper - lower) * c(0.25, 0.5, 0.75))
  }
  if (is.finite(lower)) {
    return(lower + c(0.25, 1, 2.5))
  }
  if (is.finite(upper)) {
    return(upper - c(2.5, 1, 0.25))
  }
  c(-2, 0, 2)
}

.ars_validate_initial <- function(initial, domain) {
  if (!is.numeric(initial) || length(initial) < 2L || any(!is.finite(initial))) {
    stop("initial must contain at least two finite numeric points", call. = FALSE)
  }
  initial <- sort(unique(as.numeric(initial)))
  if (length(initial) < 2L) {
    stop("initial must contain at least two distinct points", call. = FALSE)
  }
  if (any(initial <= domain[1L]) || any(initial >= domain[2L])) {
    stop("initial points must lie strictly inside domain", call. = FALSE)
  }
  initial
}

.ars_eval_log_density <- function(density_fn, x, log_density) {
  value <- tryCatch(
    density_fn(x),
    error = function(e) stop(paste("density evaluation failed:", conditionMessage(e)), call. = FALSE)
  )
  if (!is.numeric(value)) {
    stop("density must return numeric values", call. = FALSE)
  }
  if (length(value) == 1L && length(x) > 1L) {
    value <- rep(value, length(x))
  }
  if (length(value) != length(x)) {
    stop("density must return either length 1 or length equal to input length", call. = FALSE)
  }

  if (log_density) {
    h <- as.numeric(value)
  } else {
    if (any(!is.finite(value)) || any(value <= 0)) {
      stop("density must be finite and positive at all sampled/initial points", call. = FALSE)
    }
    h <- base::log(as.numeric(value))
  }
  if (any(!is.finite(h))) {
    stop("log density must be finite at all sampled/initial points", call. = FALSE)
  }
  h
}

.ars_numeric_derivative_one <- function(logdensity, x, domain) {
  base_step <- 1e-5 * (1 + abs(x))
  hx <- NULL

  for (attempt in seq_len(10L)) {
    step <- base_step / (10^(attempt - 1L))
    left <- x - step
    right <- x + step

    if (left > domain[1L] && right < domain[2L]) {
      vals <- logdensity(c(left, right))
      if (length(vals) == 2L && all(is.finite(vals))) {
        return((vals[2L] - vals[1L]) / (2 * step))
      }
    }

    if (is.null(hx)) {
      hx <- logdensity(x)
    }
    if (right < domain[2L]) {
      hr <- logdensity(right)
      if (is.finite(hr) && is.finite(hx)) {
        return((hr - hx) / step)
      }
    }
    if (left > domain[1L]) {
      hl <- logdensity(left)
      if (is.finite(hl) && is.finite(hx)) {
        return((hx - hl) / step)
      }
    }
  }

  stop("could not compute a finite numerical derivative; provide derivative explicitly", call. = FALSE)
}

.ars_eval_derivative <- function(logdensity, derivative_fn, x, domain) {
  if (!is.null(derivative_fn)) {
    value <- tryCatch(
      derivative_fn(x),
      error = function(e) stop(paste("derivative evaluation failed:", conditionMessage(e)), call. = FALSE)
    )
    if (!is.numeric(value)) {
      stop("derivative must return numeric values", call. = FALSE)
    }
    if (length(value) == 1L && length(x) > 1L) {
      value <- rep(value, length(x))
    }
    if (length(value) != length(x) || any(!is.finite(value))) {
      stop("derivative must return finite values matching the input length", call. = FALSE)
    }
    return(as.numeric(value))
  }

  vapply(x, function(xx) .ars_numeric_derivative_one(logdensity, xx, domain), numeric(1L))
}

.ars_check_state <- function(x, h, hp, domain, tol) {
  if (any(!is.finite(x)) || any(!is.finite(h)) || any(!is.finite(hp))) {
    stop("internal ARS state contains non-finite values", call. = FALSE)
  }
  if (any(diff(x) <= 0)) {
    stop("ARS abscissae must be strictly increasing", call. = FALSE)
  }

  for (i in seq_len(length(x) - 1L)) {
    scale_deriv <- 1 + abs(hp[i]) + abs(hp[i + 1L])
    if (hp[i] + tol * scale_deriv < hp[i + 1L]) {
      stop("non-log-concave density detected: log-density derivative increased", call. = FALSE)
    }

    secant <- (h[i + 1L] - h[i]) / (x[i + 1L] - x[i])
    scale_sec <- 1 + abs(secant) + abs(hp[i]) + abs(hp[i + 1L])
    if (secant > hp[i] + tol * scale_sec || secant < hp[i + 1L] - tol * scale_sec) {
      stop("non-log-concave density detected: secant slope violates concavity", call. = FALSE)
    }
  }

  if (!is.finite(domain[1L]) && hp[1L] <= 0) {
    stop("initial points must include a left point with positive log-density slope for an infinite left tail", call. = FALSE)
  }
  if (!is.finite(domain[2L]) && hp[length(hp)] >= 0) {
    stop("initial points must include a right point with negative log-density slope for an infinite right tail", call. = FALSE)
  }

  invisible(TRUE)
}

.ars_make_state <- function(initial, logdensity, derivative_fn, domain, tol) {
  x <- sort(initial)
  h <- logdensity(x)
  hp <- .ars_eval_derivative(logdensity, derivative_fn, x, domain)
  ord <- order(x)
  x <- x[ord]
  h <- h[ord]
  hp <- hp[ord]
  .ars_check_state(x, h, hp, domain, tol)
  list(x = x, h = h, hp = hp, domain = domain, tol = tol)
}

.ars_point_close <- function(x, existing) {
  any(abs(existing - x) <= 1e-8 * (1 + abs(x)))
}

.ars_add_point <- function(state, x_new, h_new, logdensity, derivative_fn) {
  if (.ars_point_close(x_new, state$x)) {
    return(state)
  }
  hp_new <- .ars_eval_derivative(logdensity, derivative_fn, x_new, state$domain)
  x <- c(state$x, x_new)
  h <- c(state$h, h_new)
  hp <- c(state$hp, hp_new)
  ord <- order(x)
  x <- x[ord]
  h <- h[ord]
  hp <- hp[ord]
  .ars_check_state(x, h, hp, state$domain, state$tol)
  list(x = x, h = h, hp = hp, domain = state$domain, tol = state$tol)
}

.ars_log_sum_exp <- function(x) {
  m <- max(x)
  m + base::log(sum(exp(x - m)))
}

.ars_log_integral_exp_linear <- function(a, b, lower, upper) {
  if (abs(b) < 1e-12) {
    if (!is.finite(lower) || !is.finite(upper)) {
      return(Inf)
    }
    return(a + base::log(upper - lower))
  }

  if (b > 0) {
    if (is.infinite(upper)) {
      return(Inf)
    }
    if (is.infinite(lower)) {
      return(a + b * upper - base::log(b))
    }
    return(a + b * upper + log1p(-exp(b * (lower - upper))) - base::log(b))
  }

  if (is.infinite(lower)) {
    return(Inf)
  }
  if (is.infinite(upper)) {
    return(a + b * lower - base::log(-b))
  }
  a + b * lower + log1p(-exp(b * (upper - lower))) - base::log(-b)
}

.ars_build_hull <- function(state) {
  x <- state$x
  h <- state$h
  hp <- state$hp
  a_all <- h - hp * x
  b_all <- hp
  merge_tol <- max(1e-8, state$tol * 1e-2)

  active <- integer(0L)
  for (j in seq_along(x)) {
    if (length(active) == 0L) {
      active <- j
      next
    }

    last <- active[length(active)]
    if (abs(b_all[j] - b_all[last]) <= merge_tol * (1 + abs(b_all[j]) + abs(b_all[last]))) {
      if (a_all[j] > a_all[last]) {
        active[length(active)] <- j
      }
    } else {
      active <- c(active, j)
    }
  }

  a <- a_all[active]
  b <- b_all[active]
  xa <- x[active]
  m <- length(active)

  if (m == 1L) {
    z <- state$domain
  } else {
    intersections <- numeric(m - 1L)
    for (i in seq_len(m - 1L)) {
      denom <- b[i] - b[i + 1L]
      if (denom <= 0) {
        stop("non-log-concave density detected while building tangent hull", call. = FALSE)
      }
      intersections[i] <- (a[i + 1L] - a[i]) / denom
      if (!is.finite(intersections[i])) {
        stop("failed to build a finite tangent intersection", call. = FALSE)
      }
      if (intersections[i] < xa[i] - 1e-6 || intersections[i] > xa[i + 1L] + 1e-6) {
        stop("non-log-concave density detected: tangent intersections are inconsistent", call. = FALSE)
      }
    }
    z <- c(state$domain[1L], intersections, state$domain[2L])
  }

  if (any(diff(z) <= 0)) {
    stop("failed to construct a valid increasing tangent hull", call. = FALSE)
  }
  if (is.infinite(z[1L]) && b[1L] <= 0) {
    stop("upper hull has a non-integrable left tail", call. = FALSE)
  }
  if (is.infinite(z[length(z)]) && b[length(b)] >= 0) {
    stop("upper hull has a non-integrable right tail", call. = FALSE)
  }

  log_weights <- vapply(seq_along(a), function(i) {
    .ars_log_integral_exp_linear(a[i], b[i], z[i], z[i + 1L])
  }, numeric(1L))

  if (any(!is.finite(log_weights))) {
    stop("upper hull is not integrable over the supplied domain", call. = FALSE)
  }

  list(a = a, b = b, z = z, log_weights = log_weights)
}

.ars_sample_truncated_exp_linear <- function(b, lower, upper) {
  u <- stats::runif(1L)
  if (abs(b) < 1e-12) {
    if (!is.finite(lower) || !is.finite(upper)) {
      stop("cannot sample a flat infinite hull segment", call. = FALSE)
    }
    return(lower + u * (upper - lower))
  }

  if (b > 0) {
    if (is.infinite(upper)) {
      stop("positive-slope right tail is not integrable", call. = FALSE)
    }
    if (is.infinite(lower)) {
      return(upper + base::log(u) / b)
    }
    q <- exp(b * (lower - upper))
    return(upper + base::log(q + u * (1 - q)) / b)
  }

  if (is.infinite(lower)) {
    stop("negative-slope left tail is not integrable", call. = FALSE)
  }
  if (is.infinite(upper)) {
    return(lower + base::log1p(-u) / b)
  }
  q <- exp(b * (upper - lower))
  lower + base::log(1 - u * (1 - q)) / b
}

.ars_sample_upper <- function(hull) {
  total <- .ars_log_sum_exp(hull$log_weights)
  probabilities <- exp(hull$log_weights - total)
  segment <- sample.int(length(probabilities), size = 1L, prob = probabilities)
  .ars_sample_truncated_exp_linear(hull$b[segment], hull$z[segment], hull$z[segment + 1L])
}

.ars_eval_upper <- function(hull, x) {
  segment <- findInterval(x, hull$z, rightmost.closed = TRUE)
  segment <- max(1L, min(segment, length(hull$a)))
  hull$a[segment] + hull$b[segment] * x
}

.ars_eval_lower <- function(state, x) {
  i <- findInterval(x, state$x)
  if (i < 1L || i >= length(state$x)) {
    return(-Inf)
  }
  x0 <- state$x[i]
  x1 <- state$x[i + 1L]
  h0 <- state$h[i]
  h1 <- state$h[i + 1L]
  h0 + (h1 - h0) * (x - x0) / (x1 - x0)
}

ars <- function(n,
                density,
                domain = c(-Inf, Inf),
                initial = NULL,
                log = FALSE,
                derivative = NULL,
                max_iter = NULL,
                max_points = 1000L,
                seed = NULL,
                verbose = FALSE,
                log_concavity_tol = 1e-4) {
  n <- .ars_validate_n(n)
  domain <- .ars_validate_domain(domain)
  if (is.null(initial)) {
    initial <- .ars_default_initial(domain)
  }
  initial <- .ars_validate_initial(initial, domain)

  if (!is.null(seed)) {
    if (!is.numeric(seed) || length(seed) != 1L || !is.finite(seed)) {
      stop("seed must be NULL or a single finite number", call. = FALSE)
    }
    set.seed(as.integer(seed))
  }

  if (is.null(max_iter)) {
    max_iter <- max(1000L, 100L * n)
  }
  if (!is.numeric(max_iter) || length(max_iter) != 1L || max_iter <= 0) {
    stop("max_iter must be a positive number", call. = FALSE)
  }
  if (!is.numeric(max_points) || length(max_points) != 1L || max_points < length(initial)) {
    stop("max_points must be at least the number of initial points", call. = FALSE)
  }
  if (!is.logical(verbose) || length(verbose) != 1L || is.na(verbose)) {
    stop("verbose must be TRUE or FALSE", call. = FALSE)
  }
  if (!is.numeric(log_concavity_tol) || length(log_concavity_tol) != 1L ||
      !is.finite(log_concavity_tol) || log_concavity_tol <= 0) {
    stop("log_concavity_tol must be a positive finite number", call. = FALSE)
  }

  env <- parent.frame()
  density_fn <- .ars_make_density_function(density, env)
  derivative_fn <- if (is.null(derivative)) NULL else .ars_make_density_function(derivative, env)
  logdensity <- function(x) .ars_eval_log_density(density_fn, x, log_density = log)

  state <- .ars_make_state(initial, logdensity, derivative_fn, domain, log_concavity_tol)
  hull <- .ars_build_hull(state)
  samples <- numeric(n)
  accepted <- 0L
  proposals <- 0L
  evaluated <- 0L

  while (accepted < n) {
    proposals <- proposals + 1L
    if (proposals > max_iter) {
      stop("ARS exceeded max_iter before drawing the requested number of samples", call. = FALSE)
    }

    candidate <- .ars_sample_upper(hull)
    if (!is.finite(candidate) || candidate <= domain[1L] || candidate >= domain[2L]) {
      stop("sampled an invalid candidate from the upper hull", call. = FALSE)
    }

    upper_value <- .ars_eval_upper(hull, candidate)
    lower_value <- .ars_eval_lower(state, candidate)
    log_u <- base::log(stats::runif(1L))

    if (is.finite(lower_value) && log_u <= lower_value - upper_value) {
      accepted <- accepted + 1L
      samples[accepted] <- candidate
      next
    }

    h_candidate <- logdensity(candidate)
    evaluated <- evaluated + 1L
    if (length(h_candidate) != 1L || !is.finite(h_candidate)) {
      stop("density evaluated to an invalid value at a sampled candidate", call. = FALSE)
    }

    envelope_tol <- max(1e-6, log_concavity_tol * (1 + abs(upper_value)))
    if (h_candidate > upper_value + envelope_tol) {
      stop("non-log-concave density detected: log density exceeded its tangent upper hull", call. = FALSE)
    }

    if (length(state$x) < max_points && !.ars_point_close(candidate, state$x)) {
      state <- .ars_add_point(state, candidate, h_candidate, logdensity, derivative_fn)
      hull <- .ars_build_hull(state)
    }

    if (log_u <= h_candidate - upper_value) {
      accepted <- accepted + 1L
      samples[accepted] <- candidate
    }
  }

  if (verbose) {
    message(sprintf(
      "ARS accepted %d samples using %d proposals, %d density evaluations, and %d hull points.",
      accepted, proposals, evaluated, length(state$x)
    ))
  }

  samples
}

.ars_report_test <- function(name, passed, values = numeric(0L), expected_mean = NA_real_,
                             expected_sd = NA_real_, extra = "") {
  observed_mean <- if (length(values) > 0L) mean(values) else NA_real_
  observed_sd <- if (length(values) > 1L) stats::sd(values) else NA_real_
  status <- if (isTRUE(passed)) "PASS" else "FAIL"
  line <- sprintf(
    "%s: %s (mean=%s, sd=%s, expected_mean=%s, expected_sd=%s%s)",
    name,
    status,
    ifelse(is.na(observed_mean), "NA", sprintf("%.4f", observed_mean)),
    ifelse(is.na(observed_sd), "NA", sprintf("%.4f", observed_sd)),
    ifelse(is.na(expected_mean), "NA", sprintf("%.4f", expected_mean)),
    ifelse(is.na(expected_sd), "NA", sprintf("%.4f", expected_sd)),
    if (nzchar(extra)) paste0(", ", extra) else ""
  )
  cat(line, "\n", sep = "")
  data.frame(test = name, passed = isTRUE(passed), mean = observed_mean, sd = observed_sd)
}

test <- function() {
  results <- list()

  set.seed(20240201)
  normal_samples <- tryCatch(
    ars(5000, dnorm, domain = c(-Inf, Inf), initial = c(-2, 0, 2), max_iter = 50000),
    error = function(e) e
  )
  normal_passed <- !inherits(normal_samples, "error") &&
    abs(mean(normal_samples)) < 0.07 &&
    abs(stats::sd(normal_samples) - 1) < 0.07 &&
    max(abs(stats::quantile(normal_samples, c(0.1, 0.5, 0.9)) - stats::qnorm(c(0.1, 0.5, 0.9)))) < 0.12
  if (!inherits(normal_samples, "error")) {
    write.table(normal_samples, "/app/normal_samples.txt", row.names = FALSE, col.names = FALSE)
  }
  results[[length(results) + 1L]] <- .ars_report_test(
    "NORMAL_SAMPLING", normal_passed,
    if (inherits(normal_samples, "error")) numeric(0L) else normal_samples,
    expected_mean = 0, expected_sd = 1,
    extra = if (inherits(normal_samples, "error")) conditionMessage(normal_samples) else "quantiles checked"
  )

  set.seed(20240202)
  exponential_samples <- tryCatch(
    ars(5000, dexp, domain = c(0, Inf), initial = c(0.25, 1, 2.5), max_iter = 50000),
    error = function(e) e
  )
  exponential_passed <- !inherits(exponential_samples, "error") &&
    abs(mean(exponential_samples) - 1) < 0.08 &&
    abs(stats::sd(exponential_samples) - 1) < 0.08 &&
    max(abs(stats::quantile(exponential_samples, c(0.1, 0.5, 0.9)) - stats::qexp(c(0.1, 0.5, 0.9)))) < 0.15
  results[[length(results) + 1L]] <- .ars_report_test(
    "EXPONENTIAL_SAMPLING", exponential_passed,
    if (inherits(exponential_samples, "error")) numeric(0L) else exponential_samples,
    expected_mean = 1, expected_sd = 1,
    extra = if (inherits(exponential_samples, "error")) conditionMessage(exponential_samples) else "quantiles checked"
  )

  derivative_points <- c(-2, -1, 0, 1, 2)
  derivative_error <- tryCatch(
    .ars_eval_derivative(function(x) stats::dnorm(x, log = TRUE), NULL, derivative_points, c(-Inf, Inf)) + derivative_points,
    error = function(e) e
  )
  derivative_passed <- !inherits(derivative_error, "error") && max(abs(derivative_error)) < 1e-5
  results[[length(results) + 1L]] <- .ars_report_test(
    "DERIVATIVE_NORMAL", derivative_passed,
    if (inherits(derivative_error, "error")) numeric(0L) else abs(derivative_error),
    expected_mean = 0, expected_sd = 0,
    extra = if (inherits(derivative_error, "error")) conditionMessage(derivative_error) else "absolute derivative error"
  )

  set.seed(20240203)
  helper_samples <- replicate(5000, .ars_sample_truncated_exp_linear(-1, 0, Inf))
  helper_passed <- abs(mean(helper_samples) - 1) < 0.08 && abs(stats::sd(helper_samples) - 1) < 0.08
  results[[length(results) + 1L]] <- .ars_report_test(
    "HULL_SAMPLER_EXPONENTIAL", helper_passed, helper_samples,
    expected_mean = 1, expected_sd = 1
  )

  invalid_n_error <- tryCatch(
    ars(-5, dnorm),
    error = function(e) e
  )
  results[[length(results) + 1L]] <- .ars_report_test(
    "INPUT_VALIDATION", inherits(invalid_n_error, "error"), numeric(0L),
    extra = if (inherits(invalid_n_error, "error")) "negative n rejected" else "negative n was not rejected"
  )

  mixture_density <- function(x) 0.5 * stats::dnorm(x, -3, 0.5) + 0.5 * stats::dnorm(x, 3, 0.5)
  non_log_concave_error <- tryCatch(
    ars(10, mixture_density, domain = c(-Inf, Inf), initial = c(-3, 0, 3), max_iter = 1000),
    error = function(e) e
  )
  results[[length(results) + 1L]] <- .ars_report_test(
    "NON_LOG_CONCAVE_REJECTION", inherits(non_log_concave_error, "error"), numeric(0L),
    extra = if (inherits(non_log_concave_error, "error")) "non-log-concave density rejected" else "density was not rejected"
  )

  invisible(do.call(rbind, results))
}
